'use client';

import { useEffect, useState } from 'react';
import {
  getProductBySlug,
  getAllProducts,
  getCategories,
  getCollections,
  checkConfig,
  type Product,
  type Category,
} from '@/sanity';

export default function TestSanityPage() {
  const [status, setStatus] = useState<{
    config: ReturnType<typeof checkConfig> | null;
    products: Pick<Product, 'slug' | 'title'>[] | null;
    categories: Category[] | null;
    product: Product | null;
    loading: boolean;
    error: string | null;
  }>({
    config: null,
    products: null,
    categories: null,
    product: null,
    loading: true,
    error: null,
  });

  useEffect(() => {
    async function testSanity() {
      try {
        setStatus((prev) => ({ ...prev, loading: true }));

        // Check configuration
        const config = checkConfig();

        // Test queries
        const [products, categories, product] = await Promise.all([
          getAllProducts(),
          getCategories(),
          getProductBySlug('tray-table').catch(() => null),
        ]);

        setStatus({
          config,
          products,
          categories,
          product,
          loading: false,
          error: null,
        });
      } catch (error) {
        setStatus({
          config: null,
          products: null,
          categories: null,
          product: null,
          loading: false,
          error: error instanceof Error ? error.message : String(error),
        });
      }
    }

    testSanity();
  }, []);

  return (
    <div className="min-h-screen bg-background p-8">
      <div className="max-w-4xl mx-auto space-y-8">
        <h1 className="text-3xl font-bold">Sanity CMS Test Page</h1>

        {/* Configuration */}
        <section className="border rounded-lg p-6">
          <h2 className="text-xl font-semibold mb-4">Configuration</h2>
          {status.config ? (
            <div className="space-y-2">
              <div>
                <span className="font-medium">Project ID:</span>{' '}
                <code className="bg-muted px-2 py-1 rounded">
                  {status.config.projectId}
                </code>
              </div>
              <div>
                <span className="font-medium">Dataset:</span>{' '}
                <code className="bg-muted px-2 py-1 rounded">
                  {status.config.dataset}
                </code>
              </div>
              <div>
                <span className="font-medium">API Version:</span>{' '}
                <code className="bg-muted px-2 py-1 rounded">
                  {status.config.apiVersion}
                </code>
              </div>
              <div>
                <span className="font-medium">Status:</span>{' '}
                <span
                  className={
                    status.config.isConfigured
                      ? 'text-green-600'
                      : 'text-red-600'
                  }
                >
                  {status.config.isConfigured ? 'Γ£à Configured' : 'Γ¥î Missing'}
                </span>
              </div>
            </div>
          ) : (
            <p className="text-muted-foreground">Loading configuration...</p>
          )}
        </section>

        {/* Error */}
        {status.error && (
          <section className="border border-red-200 bg-red-50 dark:bg-red-950 rounded-lg p-6">
            <h2 className="text-xl font-semibold mb-4 text-red-800 dark:text-red-200">
              Error
            </h2>
            <pre className="text-sm overflow-auto">
              {status.error}
            </pre>
          </section>
        )}

        {/* Loading */}
        {status.loading && (
          <section className="border rounded-lg p-6">
            <p className="text-muted-foreground">Loading data from Sanity...</p>
          </section>
        )}

        {/* Products */}
        <section className="border rounded-lg p-6">
          <h2 className="text-xl font-semibold mb-4">
            All Products ({status.products?.length || 0})
          </h2>
          {status.products && status.products.length > 0 ? (
            <ul className="space-y-2">
              {status.products.map((product) => (
                <li key={product.slug.current} className="text-sm">
                  <span className="font-medium">{product.title}</span>
                  <span className="text-muted-foreground ml-2">
                    ({product.slug.current})
                  </span>
                </li>
              ))}
            </ul>
          ) : (
            <p className="text-muted-foreground">No products found</p>
          )}
        </section>

        {/* Categories */}
        <section className="border rounded-lg p-6">
          <h2 className="text-xl font-semibold mb-4">
            Categories ({status.categories?.length || 0})
          </h2>
          {status.categories && status.categories.length > 0 ? (
            <ul className="space-y-2">
              {status.categories.map((category) => (
                <li key={category.slug.current} className="text-sm">
                  <span className="font-medium">{category.title}</span>
                  {category.icon && (
                    <span className="text-muted-foreground ml-2">
                      Icon: {category.icon}
                    </span>
                  )}
                </li>
              ))}
            </ul>
          ) : (
            <p className="text-muted-foreground">No categories found</p>
          )}
        </section>

        {/* Single Product */}
        <section className="border rounded-lg p-6">
          <h2 className="text-xl font-semibold mb-4">
            Test Product (tray-table)
          </h2>
          {status.product ? (
            <div className="space-y-4">
              <div>
                <span className="font-medium">Title:</span>{' '}
                {status.product.title}
              </div>
              <div>
                <span className="font-medium">Slug:</span>{' '}
                {status.product.slug.current}
              </div>
              <div>
                <span className="font-medium">Description:</span>{' '}
                {status.product.description || 'No description'}
              </div>
              <div>
                <span className="font-medium">Variants:</span>{' '}
                {status.product.variants?.length || 0}
              </div>
              {status.product.variants && status.product.variants.length > 0 && (
                <ul className="space-y-2 ml-4">
                  {status.product.variants.map((variant, i) => (
                    <li key={i} className="text-sm">
                      <span className="font-medium">{variant.colorName}</span>
                      {variant.imageUrl && (
                        <>
                          {' - '}
                          <a
                            href={variant.imageUrl}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="text-blue-600 hover:underline"
                          >
                            View Image
                          </a>
                        </>
                      )}
                    </li>
                  ))}
                </ul>
              )}
              <div>
                <span className="font-medium">Gallery Images:</span>{' '}
                {status.product.galleryImages?.length || 0}
              </div>
            </div>
          ) : (
            <p className="text-muted-foreground">
              Product not found (create a product with slug &quot;tray-table&quot; in
              Sanity Studio)
            </p>
          )}
        </section>
      </div>
    </div>
  );
}

"use client"

import { useEffect, useState } from "react"
import { Mail, Sparkles, CheckCircle2 } from "lucide-react"
import { getNewsletter } from "@/sanity/queries"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card, CardContent } from "@/components/ui/card"
import { cn } from "@/lib/utils"

interface NewsletterProps {
  className?: string
  variant?: "default" | "compact" | "minimal"
}

export function Newsletter({ className, variant = "default" }: NewsletterProps) {
  const [newsletter, setNewsletter] = useState<any>(null)
  const [email, setEmail] = useState("")
  const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle")
  const [message, setMessage] = useState("")

  useEffect(() => {
    getNewsletter().then((data) => {
      if (data) {
        setNewsletter(data)
      }
    })
  }, [])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!email) return

    setStatus("loading")

    // Simulate API call - replace with your actual newsletter service
    try {
      // Example: await fetch('/api/newsletter', { method: 'POST', body: JSON.stringify({ email }) })
      await new Promise((resolve) => setTimeout(resolve, 1000))
      setStatus("success")
      setMessage(newsletter?.successMessage || "Thank you for subscribing!")
      setEmail("")
      setTimeout(() => setStatus("idle"), 5000)
    } catch (error) {
      setStatus("error")
      setMessage("Something went wrong. Please try again.")
      setTimeout(() => setStatus("idle"), 5000)
    }
  }

  if (!newsletter) {
    return null
  }

  if (variant === "compact") {
    return (
      <div className={cn("bg-muted/50 rounded-xl p-6", className)}>
        <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-3">
          <div className="flex-1">
            <Input
              type="email"
              placeholder={newsletter.placeholderText || "Enter your email"}
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              disabled={status === "loading"}
              className="h-11"
            />
          </div>
          <Button
            type="submit"
            disabled={status === "loading" || status === "success"}
            className="bg-gradient-to-r from-orange-500 to-orange-600 hover:from-orange-600 hover:to-orange-700 h-11 whitespace-nowrap"
          >
            {status === "loading" ? (
              <>
                <Sparkles className="w-4 h-4 mr-2 animate-spin" />
                Subscribing...
              </>
            ) : status === "success" ? (
              <>
                <CheckCircle2 className="w-4 h-4 mr-2" />
                Subscribed!
              </>
            ) : (
              newsletter.buttonText || "Subscribe"
            )}
          </Button>
        </form>
        {status === "success" && message && (
          <p className="text-sm text-green-600 mt-2">{message}</p>
        )}
        {status === "error" && message && (
          <p className="text-sm text-destructive mt-2">{message}</p>
        )}
      </div>
    )
  }

  if (variant === "minimal") {
    return (
      <div className={cn(className)}>
        <form onSubmit={handleSubmit} className="flex items-center gap-2 max-w-md mx-auto">
          <div className="relative flex-1">
            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <Input
              type="email"
              placeholder={newsletter.placeholderText || "Enter your email"}
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              disabled={status === "loading"}
              className="pl-10"
            />
          </div>
          <Button
            type="submit"
            size="icon"
            disabled={status === "loading" || status === "success"}
            className="bg-gradient-to-r from-orange-500 to-orange-600 hover:from-orange-600 hover:to-orange-700 shrink-0"
          >
            {status === "success" ? (
              <CheckCircle2 className="w-4 h-4" />
            ) : status === "loading" ? (
              <Sparkles className="w-4 h-4 animate-spin" />
            ) : (
              <ArrowRight className="w-4 h-4" />
            )}
          </Button>
        </form>
      </div>
    )
  }

  // Default variant - full featured
  const getBgColorClass = (bgColor?: string) => {
    switch (bgColor) {
      case "orange-gradient":
        return "bg-gradient-to-r from-orange-50 via-background to-orange-50"
      case "pink-gradient":
        return "bg-gradient-to-r from-pink-50 via-background to-pink-50"
      case "muted":
        return "bg-muted"
      case "image":
        return "relative"
      default:
        return "bg-muted/30"
    }
  }

  const bgColorClass = getBgColorClass(newsletter.backgroundColor)

  return (
    <section
      className={cn(
        "py-16 md:py-24 px-4",
        bgColorClass,
        className
      )}
      style={
        newsletter.backgroundColor === "custom" && newsletter.customBackgroundColor
          ? { backgroundColor: newsletter.customBackgroundColor }
          : {}
      }
    >
      {newsletter.image && newsletter.backgroundColor === "image" && (
        <div
          className="absolute inset-0 opacity-10 -z-10"
          style={{
            backgroundImage: `url(${newsletter.image.url})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
          }}
        />
      )}

      <div className="container mx-auto max-w-3xl">
        <Card className="border-none shadow-xl">
          <CardContent className="p-8 md:p-12 text-center space-y-6">
            {/* Icon */}
            <div className="w-16 h-16 mx-auto rounded-full bg-gradient-to-br from-orange-400 to-orange-600 flex items-center justify-center">
              <Mail className="w-8 h-8 text-white" />
            </div>

            {/* Headline */}
            <h2 className="text-3xl md:text-4xl font-bold tracking-tight">
              {newsletter.headline}
            </h2>

            {/* Description */}
            {newsletter.description && (
              <p className="text-lg text-muted-foreground max-w-xl mx-auto">
                {newsletter.description}
              </p>
            )}

            {/* Discount Offer */}
            {newsletter.discountOffer && (
              <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-orange-100 text-orange-700 font-semibold">
                <Sparkles className="w-4 h-4" />
                {newsletter.discountOffer}
              </div>
            )}

            {/* Form */}
            <form onSubmit={handleSubmit} className="max-w-md mx-auto space-y-3">
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
                <Input
                  type="email"
                  placeholder={newsletter.placeholderText || "Enter your email address"}
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  disabled={status === "loading"}
                  className="pl-12 h-12 text-lg"
                />
              </div>
              <Button
                type="submit"
                disabled={status === "loading" || status === "success"}
                className="w-full bg-gradient-to-r from-orange-500 to-orange-600 hover:from-orange-600 hover:to-orange-700 text-white font-semibold h-12 text-lg"
              >
                {status === "loading" ? (
                  <>
                    <Sparkles className="w-5 h-5 mr-2 animate-spin" />
                    Subscribing...
                  </>
                ) : status === "success" ? (
                  <>
                    <CheckCircle2 className="w-5 h-5 mr-2" />
                    Subscribed!
                  </>
                ) : (
                  newsletter.buttonText || "Subscribe"
                )}
              </Button>
            </form>

            {/* Success/Error Message */}
            {status === "success" && message && (
              <p className="text-green-600 font-medium animate-in fade-in slide-in-from-bottom-2">
                {message}
              </p>
            )}
            {status === "error" && message && (
              <p className="text-destructive font-medium animate-in fade-in slide-in-from-bottom-2">
                {message}
              </p>
            )}

            {/* Privacy Note */}
            <p className="text-xs text-muted-foreground">
              We respect your privacy. Unsubscribe at any time.
            </p>
          </CardContent>
        </Card>
      </div>
    </section>
  )
}

import { ArrowRight } from "lucide-react"

export default Newsletter

import { getTestimonials } from "@/sanity/queries"
import { Star, Quote } from "lucide-react"
import Image from "next/image"
import Link from "next/link"
import { Card, CardContent } from "@/components/ui/card"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"

interface TestimonialsProps {
  featured?: boolean
  limit?: number
  className?: string
}

export async function Testimonials({ featured = true, limit = 6, className }: TestimonialsProps) {
  const testimonials = await getTestimonials(featured, limit)

  if (!testimonials || testimonials.length === 0) {
    return null
  }

  return (
    <section className={cn("py-12 md:py-16 lg:py-24", className)}>
      <div className="container mx-auto px-4 md:px-6">
        {/* Section Header */}
        <div className="text-center mb-12 md:mb-16 space-y-4">
          <Badge variant="outline" className="mb-2">
            Customer Reviews
          </Badge>
          <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold tracking-tight">
            What Our Customers Say
          </h2>
          <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
            Real reviews from real customers who love their handmade crochet pieces
          </p>
        </div>

        {/* Testimonials Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
          {testimonials.map((testimonial) => (
            <TestimonialCard key={testimonial._id} testimonial={testimonial} />
          ))}
        </div>

        {/* View All Reviews Button */}
        {featured && (
          <div className="text-center mt-12">
            <Button variant="outline" size="lg" asChild>
              <Link href="/reviews">
                View All Reviews
              </Link>
            </Button>
          </div>
        )}
      </div>
    </section>
  )
}

function TestimonialCard({ testimonial }: { testimonial: any }) {
  return (
    <Card className="overflow-hidden border-border/40 hover:shadow-lg transition-all duration-300 hover:border-primary/30 h-full">
      <CardContent className="p-6 space-y-4">
        {/* Rating */}
        <div className="flex items-center gap-1">
          {Array.from({ length: 5 }).map((_, i) => (
            <Star
              key={i}
              className={cn(
                "w-4 h-4",
                i < testimonial.rating
                  ? "fill-amber-400 text-amber-400"
                  : "fill-gray-200 text-gray-200"
              )}
            />
          ))}
        </div>

        {/* Review Text */}
        <div className="relative">
          <Quote className="absolute -top-2 -left-2 w-8 h-8 text-primary/10" />
          <p className="text-sm leading-relaxed text-foreground/90 pl-4">
            {testimonial.review}
          </p>
        </div>

        {/* Review Images */}
        {testimonial.images && testimonial.images.length > 0 && (
          <div className="flex gap-2">
            {testimonial.images.slice(0, 3).map((image: any, index: number) => (
              <div
                key={index}
                className="relative w-16 h-16 rounded-lg overflow-hidden bg-muted"
              >
                <Image
                  src={image.asset.url}
                  alt={`Review photo ${index + 1}`}
                  fill
                  className="object-cover"
                />
              </div>
            ))}
            {testimonial.images.length > 3 && (
              <div className="w-16 h-16 rounded-lg bg-muted flex items-center justify-center text-xs text-muted-foreground">
                +{testimonial.images.length - 3}
              </div>
            )}
          </div>
        )}

        {/* Customer Info */}
        <div className="flex items-center gap-3 pt-2 border-t border-border/40">
          <Avatar className="w-10 h-10">
            {testimonial.customerImage ? (
              <AvatarImage src={testimonial.customerImage.url} alt={testimonial.customerName} />
            ) : null}
            <AvatarFallback className="bg-gradient-to-br from-orange-400 to-orange-600 text-white text-sm font-medium">
              {testimonial.customerName
                .split(" ")
                .map((n: string) => n[0])
                .join("")
                .toUpperCase()
                .slice(0, 2)}
            </AvatarFallback>
          </Avatar>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-medium truncate">{testimonial.customerName}</p>
            <div className="flex items-center gap-2">
              {testimonial.isVerified && (
                <Badge variant="secondary" className="text-[10px] px-1.5 py-0">
                  Verified
                </Badge>
              )}
              {testimonial.product && (
                <Link
                  href={`/products/${testimonial.product.slug.current}`}
                  className="text-xs text-muted-foreground hover:text-primary transition-colors truncate"
                >
                  {testimonial.product.title}
                </Link>
              )}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

