"use client"

import { useState, useRef } from "react"
import Image from "next/image"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { ArrowRight, Play, Pause, Volume2, VolumeX, Maximize } from "lucide-react"
import { cn } from "@/lib/utils"

interface BrandStoryProps {
  className?: string
}

export function BrandStory({ className }: BrandStoryProps) {
  const videoRef = useRef<HTMLVideoElement>(null)
  const [isPlaying, setIsPlaying] = useState(true)
  const [isMuted, setIsMuted] = useState(false)
  const [showControls, setShowControls] = useState(false)

  const togglePlay = () => {
    if (videoRef.current) {
      if (isPlaying) {
        videoRef.current.pause()
      } else {
        videoRef.current.play()
      }
      setIsPlaying(!isPlaying)
    }
  }

  const toggleMute = () => {
    if (videoRef.current) {
      videoRef.current.muted = !isMuted
      setIsMuted(!isMuted)
    }
  }

  const toggleFullscreen = () => {
    if (videoRef.current) {
      if (document.fullscreenElement) {
        document.exitFullscreen()
      } else {
        videoRef.current.requestFullscreen()
      }
    }
  }

  return (
    <section
      className={cn("py-12 md:py-16 lg:py-24 bg-background", className)}
      onMouseEnter={() => setShowControls(true)}
      onMouseLeave={() => setShowControls(false)}
    >
      <div className="container mx-auto px-4 md:px-6">
        <div className="grid lg:grid-cols-2 gap-12 lg:gap-16 items-center">
          {/* Content Column */}
          <div className="space-y-6 order-2 lg:order-1 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            {/* Badge */}
            <Badge className="w-fit bg-primary/10 text-primary hover:bg-primary/20 border-primary/20">
              Our Story
            </Badge>

            {/* Heading */}
            <div className="space-y-4">
              <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold tracking-tight">
                Handcrafted with Love Since 2020
              </h2>
              <p className="text-muted-foreground text-base md:text-lg leading-relaxed">
                Since 2020, Hassan Crochet has been creating unique, customizable crochet pieces that
                bring warmth and personality to your home. Each product is lovingly handcrafted with
                attention to detail and quality materials.
              </p>
              <p className="text-muted-foreground text-base md:text-lg leading-relaxed">
                From cozy tray tables to decorative accessories, every piece tells a story of
                craftsmanship and care. We believe in creating products that become cherished
                parts of your home.
              </p>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-3 gap-4 pt-4">
              <div className="text-center p-4 rounded-xl bg-muted/30 hover:bg-muted/50 transition-colors animate-in fade-in slide-in-from-bottom-4 duration-1000 delay-100">
                <div className="text-2xl md:text-3xl font-bold text-primary">5K+</div>
                <div className="text-xs md:text-sm text-muted-foreground mt-1">Happy Customers</div>
              </div>
              <div className="text-center p-4 rounded-xl bg-muted/30 hover:bg-muted/50 transition-colors animate-in fade-in slide-in-from-bottom-4 duration-1000 delay-200">
                <div className="text-2xl md:text-3xl font-bold text-primary">50+</div>
                <div className="text-xs md:text-sm text-muted-foreground mt-1">Unique Designs</div>
              </div>
              <div className="text-center p-4 rounded-xl bg-muted/30 hover:bg-muted/50 transition-colors animate-in fade-in slide-in-from-bottom-4 duration-1000 delay-300">
                <div className="text-2xl md:text-3xl font-bold text-primary">100%</div>
                <div className="text-xs md:text-sm text-muted-foreground mt-1">Handmade</div>
              </div>
            </div>

            {/* CTA Button */}
            <div className="pt-4 animate-in fade-in slide-in-from-bottom-4 duration-1000 delay-500">
              <Button size="lg" className="group" asChild>
                <Link href="/products">
                  Explore Our Collection
                  <ArrowRight className="ml-2 h-4 w-4 transition-transform group-hover:translate-x-1" />
                </Link>
              </Button>
            </div>
          </div>

          {/* Video Column */}
          <div className="order-1 lg:order-2 animate-in fade-in slide-in-from-right-4 duration-1000">
            <div className="relative aspect-[4/5] rounded-2xl overflow-hidden shadow-2xl bg-muted group">
              <video
                ref={videoRef}
                src="/videos/video1.mp4"
                autoPlay
                loop
                playsInline
                muted={isMuted}
                className="w-full h-full object-cover"
              />
              {/* Overlay Gradient */}
              <div className="absolute inset-0 bg-gradient-to-t from-primary/20 to-transparent" />

              {/* Custom Controls */}
              <div
                className={cn(
                  "absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/80 via-black/50 to-transparent p-4 transition-opacity duration-300",
                  showControls || !isPlaying ? "opacity-100" : "opacity-0"
                )}
              >
                {/* Progress Bar */}
                <div className="mb-3">
                  <div className="h-1 bg-white/30 rounded-full overflow-hidden cursor-pointer group/progress">
                    <div
                      className="h-full bg-white rounded-full transition-all duration-100"
                      style={{
                        width: videoRef.current
                          ? `${(videoRef.current.currentTime / videoRef.current.duration) * 100}%`
                          : "0%"
                      }}
                    />
                  </div>
                </div>

                {/* Control Buttons */}
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    {/* Play/Pause */}
                    <button
                      onClick={togglePlay}
                      className="p-2 rounded-full bg-white/20 hover:bg-white/30 transition-colors"
                      aria-label={isPlaying ? "Pause" : "Play"}
                    >
                      {isPlaying ? (
                        <Pause className="h-5 w-5 text-white" />
                      ) : (
                        <Play className="h-5 w-5 text-white" />
                      )}
                    </button>

                    {/* Mute/Unmute */}
                    <button
                      onClick={toggleMute}
                      className="p-2 rounded-full bg-white/20 hover:bg-white/30 transition-colors"
                      aria-label={isMuted ? "Unmute" : "Mute"}
                    >
                      {isMuted ? (
                        <VolumeX className="h-5 w-5 text-white" />
                      ) : (
                        <Volume2 className="h-5 w-5 text-white" />
                      )}
                    </button>
                  </div>

                  {/* Fullscreen */}
                  <button
                    onClick={toggleFullscreen}
                    className="p-2 rounded-full bg-white/20 hover:bg-white/30 transition-colors"
                    aria-label="Fullscreen"
                  >
                    <Maximize className="h-5 w-5 text-white" />
                  </button>
                </div>
              </div>

              {/* Center Play/Pause Button (shows on hover when paused) */}
              {!isPlaying && (
                <div className="absolute inset-0 flex items-center justify-center bg-black/30">
                  <button
                    onClick={togglePlay}
                    className="p-4 rounded-full bg-white/90 hover:bg-white transition-transform hover:scale-110"
                    aria-label="Play"
                  >
                    <Play className="h-8 w-8 text-primary fill-primary" />
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </section>
  )
}

'use client'

import React, { useState } from "react"
import Image from "next/image"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Card, CardContent } from "@/components/ui/card"
import { cn } from "@/lib/utils"
import { Heart, ShoppingCart, Star } from "lucide-react"
import type { Product } from "@/sanity/queries"

interface ProductCardProps {
  product: Product
  variant?: "default" | "featured" | "compact"
  className?: string
  price?: number
  comparePrice?: number
  rating?: number
  reviewCount?: number
}

export function ProductCard({
  product,
  variant = "default",
  className,
  price,
  comparePrice,
  rating,
  reviewCount
}: ProductCardProps) {
  const [isFavorited, setIsFavorited] = useState(false)
  const [imageLoaded, setImageLoaded] = useState(false)

  const firstVariant = product.variants?.[0]
  const productImage = product.mainImageUrl || firstVariant?.imageUrl
  const productSlug = product.slug?.current
  const isSale = comparePrice && price != null && comparePrice > price
  const isNew = product.badges?.some(b => b.toLowerCase() === "new")
  const isBestseller = product.badges?.some(b => b.toLowerCase().includes("best"))

  if (!productSlug) return null

  // Compact variant for list views
  if (variant === "compact") {
    return (
      <Link href={`/products/${productSlug}`} className={cn("group block", className)}>
        <div className="flex gap-4 p-4 bg-white rounded-lg border border-gray-100 hover:border-gray-200 hover:shadow-md transition-all">
          {/* Thumbnail */}
          <div className="relative w-20 h-20 flex-shrink-0 rounded overflow-hidden bg-gray-50">
            {productImage ? (
              <Image
                src={productImage}
                alt={product.title}
                fill
                className="object-cover"
                sizes="80px"
              />
            ) : (
              <div className="w-full h-full bg-gray-100 flex items-center justify-center">
                <span className="text-xs text-gray-400">No img</span>
              </div>
            )}
          </div>

          {/* Info */}
          <div className="flex-1 min-w-0 flex flex-col justify-between">
            <div>
              <h3 className="font-medium text-sm text-gray-900 line-clamp-1">
                {product.title}
              </h3>
              {product.category && (
                <p className="text-xs text-gray-500 mt-0.5">{product.category.title}</p>
              )}
            </div>
            <div className="flex items-center justify-between">
              {price ? (
                <span className="text-sm font-semibold text-gray-900">
                  ${price.toFixed(2)}
                </span>
              ) : (
                <span className="text-sm font-medium text-primary">Custom</span>
              )}
              <button
                onClick={(e) => {
                  e.preventDefault()
                  setIsFavorited(!isFavorited)
                }}
                className="text-gray-400 hover:text-red-500 transition-colors"
              >
                <Heart className={cn("w-4 h-4", isFavorited && "fill-red-500 text-red-500")} />
              </button>
            </div>
          </div>
        </div>
      </Link>
    )
  }

  return (
    <Card className={cn(
      "group border border-gray-100 bg-white overflow-hidden hover:shadow-lg transition-all duration-300",
      variant === "featured" && "md:col-span-2 lg:col-span-1",
      className
    )}>
      <CardContent className="p-0">
        <Link href={`/products/${productSlug}`}>
          {/* Image Container */}
          <div className="relative aspect-square overflow-hidden bg-gray-50">
            {productImage && productImage.length > 0 ? (
              <Image
                src={productImage}
                alt={product.title}
                fill
                className="object-cover group-hover:scale-105 transition-transform duration-300"
                sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 25vw"
              />
            ) : (
              <div className="w-full h-full bg-gray-100 flex items-center justify-center">
                <span className="text-sm text-gray-400">No image</span>
              </div>
            )}

            {/* Badge - Top Left */}
            {isNew && (
              <div className="absolute top-3 left-3">
                <Badge className="bg-emerald-500 hover:bg-emerald-600 text-white text-xs font-semibold px-2.5 py-1 rounded-md">
                  NEW
                </Badge>
              </div>
            )}

            {isBestseller && !isNew && (
              <div className="absolute top-3 left-3">
                <Badge className="bg-amber-500 hover:bg-amber-600 text-white text-xs font-semibold px-2.5 py-1 rounded-md">
                  BESTSELLER
                </Badge>
              </div>
            )}

            {/* Sale Badge */}
            {isSale && (
              <div className="absolute top-3 right-3">
                <Badge className="bg-red-500 hover:bg-red-600 text-white text-xs font-bold px-2.5 py-1 rounded-md">
                  -{Math.round((1 - price / comparePrice!) * 100)}%
                </Badge>
              </div>
            )}

            {/* Favorite Button */}
            <button
              onClick={(e) => {
                e.preventDefault()
                setIsFavorited(!isFavorited)
              }}
              className={cn(
                "absolute bottom-3 right-3 w-9 h-9 rounded-full flex items-center justify-center transition-all",
                "bg-white shadow-md hover:shadow-lg hover:scale-105",
                isFavorited && "bg-red-50"
              )}
            >
              <Heart className={cn(
                "w-4 h-4 transition-colors",
                isFavorited ? "fill-red-500 text-red-500" : "text-gray-600 hover:text-red-500"
              )} />
            </button>
          </div>

          {/* Product Info */}
          <div className="p-4 space-y-3">
            {/* Category */}
            {product.category && (
              <p className="text-xs text-gray-500 uppercase tracking-wide">
                {product.category.title}
              </p>
            )}

            {/* Title */}
            <h3 className="font-medium text-base text-gray-900 line-clamp-2 group-hover:text-primary transition-colors">
              {product.title}
            </h3>

            {/* Rating */}
            {(isBestseller || rating) && rating && (
              <div className="flex items-center gap-1">
                <div className="flex">
                  {[...Array(5)].map((_, i) => (
                    <Star
                      key={i}
                      className={cn(
                        "w-3.5 h-3.5",
                        i < Math.floor(rating)
                          ? "fill-amber-400 text-amber-400"
                          : "text-gray-200"
                      )}
                    />
                  ))}
                </div>
                <span className="text-xs text-gray-500">
                  {rating} {reviewCount && `(${reviewCount})`}
                </span>
              </div>
            )}

            {/* Price */}
            <div className="flex items-center gap-2">
              {price ? (
                <>
                  <span className={cn(
                    "text-lg font-bold text-gray-900",
                    isSale && "text-red-600"
                  )}>
                    ${price.toFixed(2)}
                  </span>
                  {isSale && comparePrice && (
                    <span className="text-sm text-gray-400 line-through">
                      ${comparePrice.toFixed(2)}
                    </span>
                  )}
                </>
              ) : (
                <span className="text-lg font-bold text-primary">Custom</span>
              )}
            </div>

            {/* Color Swatches */}
            {product.variants && product.variants.length > 1 && (
              <div className="flex items-center gap-1.5 pt-1">
                {product.variants.slice(0, 4).map((variant, index) => (
                  <button
                    key={index}
                    className="w-5 h-5 rounded-full border-2 border-white shadow-sm hover:scale-110 transition-transform"
                    style={{
                      backgroundColor: variant.colorValue || "#ccc"
                    }}
                    title={variant.colorName}
                  />
                ))}
                {product.variants.length > 4 && (
