"use client"

import * as React from "react"
import Link from "next/link"
import { useRouter, useSearchParams } from "next/navigation"
import { Search, X, Loader2 } from "lucide-react"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"
import type { Product } from "@/sanity/queries"

interface SearchDropdownProps {
  placeholder?: string
  className?: string
}

export function SearchDropdown({ placeholder = "Search products...", className }: SearchDropdownProps) {
  const [query, setQuery] = React.useState("")
  const [isOpen, setIsOpen] = React.useState(false)
  const [results, setResults] = React.useState<Product[]>([])
  const [isLoading, setIsLoading] = React.useState(false)
  const [inputRef, setInputRef] = React.useState<HTMLInputElement | null>(null)
  const router = useRouter()
  const searchParams = useSearchParams()

  // Debounced search
  React.useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.trim().length >= 2) {
        setIsLoading(true)
        try {
          const response = await fetch(`/api/search?q=${encodeURIComponent(query.trim())}`)
          const data = await response.json()
          setResults(data.results || [])
        } catch (error) {
          console.error("Search error:", error)
          setResults([])
        } finally {
          setIsLoading(false)
        }
        setIsOpen(true)
      } else {
        setResults([])
        setIsOpen(false)
      }
    }, 300)

    return () => clearTimeout(timer)
  }, [query])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (query.trim()) {
      router.push(`/search?q=${encodeURIComponent(query.trim())}`)
      setIsOpen(false)
      inputRef?.blur()
    }
  }

  const handleClear = () => {
    setQuery("")
    setResults([])
    setIsOpen(false)
    inputRef?.focus()
  }

  const handleProductClick = () => {
    setIsOpen(false)
    setQuery("")
    setResults([])
  }

  return (
    <div className={cn("relative", className)}>
      <form onSubmit={handleSubmit} className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
        <Input
          ref={setInputRef}
          type="search"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onFocus={() => {
            if (query.trim().length >= 2) setIsOpen(true)
          }}
          placeholder={placeholder}
          className={cn("pl-10 pr-10", isOpen && "rounded-b-none border-b-0 focus-visible:rounded-b-none")}
        />
        {query && (
          <button
            type="button"
            onClick={handleClear}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
          >
            <X className="h-4 w-4" />
          </button>
        )}
      </form>

      {/* Search Results Dropdown */}
      {isOpen && (
        <>
          {/* Backdrop */}
          <div
            className="fixed inset-0 z-10"
            onClick={() => setIsOpen(false)}
          />

          {/* Results */}
          <Card className="absolute top-full left-0 right-0 z-20 rounded-t-none shadow-lg max-h-[80vh] overflow-hidden flex flex-col">
            <CardContent className="p-0">
              {isLoading ? (
                <div className="py-8 flex items-center justify-center">
                  <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                </div>
              ) : results.length > 0 ? (
                <div className="py-2">
                  <div className="px-4 py-2 text-xs font-semibold text-muted-foreground uppercase">
                    Products ({results.length})
                  </div>
                  {results.slice(0, 6).map((product) => (
                    <Link
                      key={product._id}
                      href={`/products/${product.slug?.current}`}
                      onClick={handleProductClick}
                      className="flex items-center gap-4 px-4 py-3 hover:bg-muted/50 transition-colors border-b border-border/40 last:border-0"
                    >
                      {/* Product Image */}
                      <div className="w-12 h-12 rounded-lg bg-muted overflow-hidden flex-shrink-0 relative">
                        {product.variants?.[0]?.imageUrl ? (
                          <img
                            src={product.variants[0].imageUrl}
                            alt={product.title}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full bg-muted flex items-center justify-center">
                            <span className="text-xs text-muted-foreground">No img</span>
                          </div>
                        )}
                      </div>

                      {/* Product Info */}
                      <div className="flex-1 min-w-0">
                        <h4 className="font-medium text-sm truncate">{product.title}</h4>
                        {product.shortDescription && (
                          <p className="text-xs text-muted-foreground truncate">
                            {product.shortDescription}
                          </p>
                        )}
                        {product.category && (
                          <span className="text-xs text-muted-foreground">
                            {product.category.title}
                          </span>
                        )}
                      </div>

                      {/* Badges */}
                      {product.badges && product.badges.length > 0 && (
                        <Badge className="text-xs px-2 py-0.5 bg-primary/20 text-primary hover:bg-primary/30">
                          {product.badges[0]}
                        </Badge>
                      )}
                    </Link>
                  ))}

                  {/* View All Results */}
                  {results.length > 6 && (
                    <Link
                      href={`/search?q=${encodeURIComponent(query.trim())}`}
                      onClick={handleProductClick}
                      className="block px-4 py-3 text-center text-sm font-medium text-primary hover:bg-muted/50 transition-colors border-t border-border/40"
                    >
                      View all {results.length} results
                    </Link>
                  )}
                </div>
              ) : query.trim().length >= 2 ? (
                <div className="py-8 text-center">
                  <p className="text-sm text-muted-foreground">No products found</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    Try different keywords
                  </p>
                </div>
              ) : null}
            </CardContent>
          </Card>
        </>
      )}
    </div>
  )
}

import { searchProducts } from "@/sanity/queries"
import { ProductCard } from "@/components/home/ProductCard"

interface SearchResultsProps {
  query: string
}

export async function SearchResults({ query }: SearchResultsProps) {
  const products = await searchProducts(query)

  if (!products || products.length === 0) {
    return (
      <div className="text-center py-16">
        <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-muted mb-4">
          <svg className="w-6 h-6 text-muted-foreground" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        </div>
        <h2 className="text-xl font-semibold mb-2">No products found</h2>
        <p className="text-muted-foreground mb-6">
          We couldn't find any products matching "{query}"
        </p>
        <p className="text-sm text-muted-foreground">
          Try searching for "crochet", "sweater", "basket", or browse our{" "}
          <a href="/products" className="text-primary hover:underline">
            all products
          </a>
        </p>
      </div>
    )
  }

  return (
    <div>
      <p className="text-sm text-muted-foreground mb-6">
        Found {products.length} product{products.length !== 1 ? "s" : ""}
      </p>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {products.map((product) => (
          <ProductCard key={product._id} product={product} />
        ))}
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Input } from "@/components/ui/input"
import { Separator } from "@/components/ui/separator"
import { Card, CardContent } from "@/components/ui/card"
import { cn } from "@/lib/utils"
import { ChevronLeft, ChevronRight, Heart, Minus, Plus } from "lucide-react"

// Color Selector Component
export interface ColorOption {
  name: string
  value: string
  imageUrl?: string
}

interface ColorSelectorProps {
  colors: ColorOption[]
  selectedColor: ColorOption
  onSelectColor: (color: ColorOption) => void
  className?: string
}

export function ColorSelector({ colors, selectedColor, onSelectColor, className }: ColorSelectorProps) {
  return (
    <div className={cn("space-y-3", className)}>
      <div className="flex justify-between items-center">
        <label className="text-sm font-medium">Select Color</label>
        <span className="text-sm text-muted-foreground capitalize">{selectedColor?.name}</span>
      </div>
      <div className="flex gap-3">
        {colors.map((color) => (
          <TooltipWrapper key={color.name} content={color.name}>
            <button
              onClick={() => onSelectColor(color)}
              aria-label={color.name}
              className={cn(
                "relative w-12 h-12 rounded-full transition-all duration-200 flex items-center justify-center",
                selectedColor?.name === color.name
                  ? "scale-110 shadow-lg ring-2 ring-ring ring-offset-2"
                  : "hover:scale-105 opacity-80 hover:opacity-100"
              )}
            >
              {color.imageUrl ? (
                <img
                  src={color.imageUrl}
                  alt={color.name}
                  className="w-full h-full object-cover rounded-full"
                />
              ) : (
                <div
                  className="w-full h-full rounded-full"
                  style={{ backgroundColor: color.value }}
                />
              )}
              {selectedColor?.name === color.name && (
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-2 h-2 bg-white rounded-full shadow-sm" />
                </div>
              )}
            </button>
          </TooltipWrapper>
        ))}
      </div>
    </div>
  )
}

// Quantity Selector Component
interface QuantitySelectorProps {
  quantity: number
  onQuantityChange: (quantity: number) => void
  min?: number
  max?: number
  className?: string
}

export function QuantitySelector({
  quantity,
  onQuantityChange,
  min = 1,
  max = 99,
  className
}: QuantitySelectorProps) {
  const handleDecrement = () => {
    if (quantity > min) {
      onQuantityChange(quantity - 1)
    }
  }

  const handleIncrement = () => {
    if (quantity < max) {
      onQuantityChange(quantity + 1)
    }
  }

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = parseInt(e.target.value)
    if (!isNaN(value) && value >= min && value <= max) {
      onQuantityChange(value)
    }
  }

  return (
    <div className={cn("flex items-center", className)}>
      <div className="flex items-center border border-input rounded-lg overflow-hidden">
        <Button
          type="button"
          variant="ghost"
          size="icon"
          onClick={handleDecrement}
          disabled={quantity <= min}
          className="h-10 w-10 rounded-none"
        >
          <Minus className="h-4 w-4" />
        </Button>
        <Input
          type="number"
          value={quantity}
          onChange={handleInputChange}
          min={min}
          max={max}
          className="h-10 w-16 border-0 text-center focus-visible:ring-0"
        />
        <Button
          type="button"
          variant="ghost"
          size="icon"
          onClick={handleIncrement}
          disabled={quantity >= max}
          className="h-10 w-10 rounded-none"
        >
          <Plus className="h-4 w-4" />
        </Button>
      </div>
    </div>
  )
}

// Image Gallery Component
interface ImageGalleryProps {
  images: string[]
  currentIndex: number
  onIndexChange: (index: number) => void
  badges?: Array<{ label: string; variant?: "default" | "secondary" | "destructive" | "outline" }>
  className?: string
}

export function ImageGallery({
  images,
  currentIndex,
  onIndexChange,
  badges = [],
  className
}: ImageGalleryProps) {
  const goToPrevious = () => {
    onIndexChange((currentIndex - 1 + images.length) % images.length)
  }

  const goToNext = () => {
    onIndexChange((currentIndex + 1) % images.length)
  }

  return (
    <div className={cn("space-y-4", className)}>
      <Card className="overflow-hidden">
        <CardContent className="p-0 relative aspect-square">
          {/* Badges */}
          {badges.length > 0 && (
            <div className="absolute top-4 left-4 z-10 flex flex-col gap-2">
              {badges.map((badge, index) => (
                <Badge key={index} variant={badge.variant || "default"}>
                  {badge.label}
                </Badge>
              ))}
            </div>
          )}

          {/* Main Image */}
          <img
            src={images[currentIndex]}
            alt={`Product view ${currentIndex + 1}`}
            className="w-full h-full object-cover"
          />

          {/* Navigation Buttons */}
          {images.length > 1 && (
            <>
              <Button
                variant="secondary"
                size="icon"
                onClick={goToPrevious}
                className="absolute left-4 top-1/2 -translate-y-1/2 h-10 w-10 rounded-full shadow-lg"
              >
                <ChevronLeft className="h-5 w-5" />
              </Button>
              <Button
                variant="secondary"
                size="icon"
                onClick={goToNext}
                className="absolute right-4 top-1/2 -translate-y-1/2 h-10 w-10 rounded-full shadow-lg"
              >
                <ChevronRight className="h-5 w-5" />
              </Button>
            </>
          )}
        </CardContent>
      </Card>

      {/* Thumbnails */}
      {images.length > 1 && (
        <div className="flex gap-3 overflow-x-auto pb-2">
          {images.map((image, index) => (
            <button
              key={index}
              onClick={() => onIndexChange(index)}
              className={cn(
                "relative flex-shrink-0 w-20 aspect-square rounded-lg overflow-hidden transition-all",
                currentIndex === index
                  ? "ring-2 ring-primary ring-offset-2"
                  : "hover:ring-2 hover:ring-muted-foreground hover:ring-offset-2"
              )}
            >
              <img
                src={image}
                alt={`Thumbnail ${index + 1}`}
                className="w-full h-full object-cover"
              />
            </button>
          ))}
        </div>
      )}
    </div>
  )
}

// Countdown Timer Component
interface CountdownTimerProps {
  endDate: Date
  onComplete?: () => void
  className?: string
}

export function CountdownTimer({ endDate, onComplete, className }: CountdownTimerProps) {
  const [timeLeft, setTimeLeft] = React.useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  })

  React.useEffect(() => {
    const calculateTimeLeft = () => {
      const difference = endDate.getTime() - new Date().getTime()

      if (difference <= 0) {
        onComplete?.()
        return { days: 0, hours: 0, minutes: 0, seconds: 0 }
      }

      return {
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      }
    }

    setTimeLeft(calculateTimeLeft())

    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft())
    }, 1000)

    return () => clearInterval(timer)
  }, [endDate, onComplete])

  const TimeBlock = ({ value, label }: { value: number; label: string }) => (
    <div className="flex flex-col items-center">
      <div className="bg-muted rounded-lg px-4 py-3 min-w-[70px]">
        <span className="text-2xl font-semibold tabular-nums">
          {String(value).padStart(2, "0")}
        </span>
      </div>
      <span className="text-xs text-muted-foreground mt-1">{label}</span>
    </div>
  )

  return (
    <div className={cn("space-y-3", className)}>
      <p className="text-sm font-medium">Offer expires in:</p>
      <div className="flex gap-3">
        <TimeBlock value={timeLeft.days} label="Days" />
        <TimeBlock value={timeLeft.hours} label="Hours" />
        <TimeBlock value={timeLeft.minutes} label="Minutes" />
        <TimeBlock value={timeLeft.seconds} label="Seconds" />
      </div>
    </div>
  )
}

// Add to Cart Button Component
interface AddToCartButtonProps {
  isFavorite?: boolean
  onToggleFavorite?: () => void
  onAddToCart?: () => void
  showWishlist?: boolean
  className?: string
}

export function AddToCartButton({
  isFavorite = false,
  onToggleFavorite,
  onAddToCart,
  showWishlist = true,
  className
}: AddToCartButtonProps) {
  return (
    <div className={cn("flex gap-3", className)}>
      <Button onClick={onAddToCart} size="lg" className="flex-1">
        Add to Cart
      </Button>
      {showWishlist && (
        <Button
          variant="outline"
          size="lg"
          onClick={onToggleFavorite}
          className="shrink-0"
        >
          <Heart
            className={cn(
              "h-5 w-5",
              isFavorite && "fill-current text-destructive"
            )}
          />
        </Button>
      )}
    </div>
  )
}

// Tooltip Wrapper (simple inline tooltip)
function TooltipWrapper({ children, content }: { children: React.ReactNode; content: string }) {
  return (
    <div className="group relative inline-block">
      {children}
      <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-primary text-primary-foreground text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap">
        {content}
      </div>
    </div>
  )
}

// Product Price Component
interface ProductPriceProps {
  price: number
  comparePrice?: number
  className?: string
}

export function ProductPrice({ price, comparePrice, className }: ProductPriceProps) {
  return (
    <div className={cn("flex items-baseline gap-3", className)}>
      <span className="text-3xl font-bold">${price.toFixed(2)}</span>
